const API_BASE = "http://localhost:3000";

const api = {

  getHomeList: async () => {
    const res = await fetch(`${API_BASE}/movies`);
    const movies = await res.json();

    return [
      {
        slug: "all",
        title: "Originais",
        items: { results: movies }
      },
      {
        slug: "all2",
        title: "Recomendados",
        items: { results: movies }
      },
      {
        slug: "all3",
        title: "Em Alta",
        items: { results: movies }
      }
    ];
  },

  getMovieInfo: async (movieId) => {
    const res = await fetch(`${API_BASE}/movies`);
    const movies = await res.json();

    return movies.find(m => m.id === movieId) || null;
  }

};

export default api;
